const raw = $input.first().json.output || $input.first().json.text || '';

let parsed;

// ── Step 1: Try to parse agent JSON output ──
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON block found');
  parsed = JSON.parse(jsonMatch[0]);
} catch(e) {
  const lower = raw.toLowerCase();
  parsed = {
    tool_called: 'unknown',
    query_understood: '',
    needs_input: lower.includes('please provide') || lower.includes('missing'),
    missing_param: null,
    missing_param_prompt: null,
    display_type: 'error',
    summary: raw.slice(0, 300),
    columns: [], rows: [], single_record: {},
    boolean_result: null, total_count: 0,
    error: true, error_message: raw.slice(0, 300)
  };
}

// ── Step 2: Unwrap ServiceResponse structure ──
// Handles: { serviceResponse: { customerList: [...] } }
// Also handles raw arrays or direct data objects
function unwrapServiceResponse(data) {
  if (!data || typeof data !== 'object') return { list: [], single: null };

  // Top-level serviceResponse wrapper
  const sr = data.serviceResponse || data.ServiceResponse || data;

  // Known list keys in CP management API responses
  const listKeys = [
    'customerList', 'transactionList', 'feeList', 'pendingList',
    'data', 'list', 'records', 'result', 'results', 'content'
  ];

  for (const key of listKeys) {
    if (sr[key] && Array.isArray(sr[key])) {
      return { list: sr[key], single: null, status: data.serviceStatus || '' };
    }
  }

  // If sr itself is an array
  if (Array.isArray(sr)) {
    return { list: sr, single: null, status: data.serviceStatus || '' };
  }

  // Boolean / existence check
  if (typeof sr === 'boolean' || sr === true || sr === false) {
    return { list: [], single: null, boolean: sr, status: data.serviceStatus || '' };
  }
  if (typeof data === 'boolean') {
    return { list: [], single: null, boolean: data, status: '' };
  }

  // Single object (customer profile, pending status)
  if (typeof sr === 'object' && !Array.isArray(sr)) {
    const keys = Object.keys(sr);
    // If it looks like a single record (has id or customerId)
    if (keys.includes('id') || keys.includes('customerId')) {
      return { list: [sr], single: sr, status: data.serviceStatus || '' };
    }
    // Wrap any remaining object as single
    return { list: [sr], single: sr, status: data.serviceStatus || '' };
  }

  return { list: [], single: null, status: '' };
}

// ── Step 3: Flatten nested objects for table display ──
function flattenRecord(record, prefix) {
  if (!record || typeof record !== 'object') return {};
  const flat = {};
  for (const [k, v] of Object.entries(record)) {
    const key = prefix ? `${prefix}.${k}` : k;
    if (v === null || v === undefined) {
      flat[key] = null;
    } else if (Array.isArray(v)) {
      // For nested arrays (br, commercialPaper) store count instead of full array
      flat[key] = `[${v.length} record${v.length !== 1 ? 's' : ''}]`;
    } else if (typeof v === 'object') {
      // Flatten one level deep
      Object.assign(flat, flattenRecord(v, key));
    } else {
      flat[key] = v;
    }
  }
  return flat;
}

// Priority columns to show first for customer records
const PRIORITY_COLS = [
  'customerId', 'customerName', 'email', 'contactNumber',
  'status', 'ipaFees', 'ipaFrequency', 'totalFees',
  'accountNumber', 'designatedAccountNumber',
  'createdOn', 'updatedOn', 'isUserActive'
];

// Columns to exclude from table (noisy / always null)
const EXCLUDE_COLS = [
  'filePath', 'mailIdList', 'makerMailId',
  'isIPAAggrement', 'isEmailFaxEndemnity', 'emailFaxEndemnityDoc',
  'address1', 'address2', 'contact1', 'contact2', 'contact3',
  'isDefaulter', 'defaultDate', 'defaultPeriodEndDate',
  'isDefaulterInformed', 'informDate', 'defaulterDoc',
  'ipaAggrementDoc'
];

function buildColumns(rows) {
  if (!rows.length) return [];
  const allKeys = [...new Set(rows.flatMap(r => Object.keys(r)))];
  const filtered = allKeys.filter(k => !EXCLUDE_COLS.includes(k));

  // Sort: priority first, then rest alphabetically
  const priority = PRIORITY_COLS.filter(k => filtered.includes(k));
  const rest = filtered.filter(k => !PRIORITY_COLS.includes(k)).sort();
  return [...priority, ...rest];
}

// ── Step 4: Try to parse raw API response if agent embedded it ──
let apiData = null;
try {
  if (parsed.raw_response) {
    apiData = typeof parsed.raw_response === 'string'
      ? JSON.parse(parsed.raw_response)
      : parsed.raw_response;
  } else if (parsed.rows && parsed.rows.length > 0) {
    // Agent already extracted rows — use them directly
    apiData = null;
  }
} catch(e) { apiData = null; }

// ── Step 5: Build final output ──
let rows = Array.isArray(parsed.rows) ? parsed.rows : [];
let columns = Array.isArray(parsed.columns) ? parsed.columns : [];
let boolean_result = parsed.boolean_result !== undefined ? parsed.boolean_result : null;
let display_type = parsed.display_type || 'table';
let summary = parsed.summary || '';

// If agent gave us rows, flatten them
if (rows.length > 0) {
  rows = rows.map(r => typeof r === 'object' && r !== null ? flattenRecord(r) : r);
  if (columns.length === 0) columns = buildColumns(rows);
}

// If agent gave no rows but we have raw API data from the response, unwrap it
if (rows.length === 0 && apiData) {
  const unwrapped = unwrapServiceResponse(apiData);
  if (unwrapped.boolean !== undefined) {
    boolean_result = unwrapped.boolean;
    display_type = 'boolean';
  } else if (unwrapped.list.length > 0) {
    rows = unwrapped.list.map(r => flattenRecord(r));
    columns = buildColumns(rows);
    display_type = 'table';
    summary = summary || `Found ${rows.length} record(s).`;
  } else if (unwrapped.single) {
    rows = [flattenRecord(unwrapped.single)];
    columns = buildColumns(rows);
    display_type = 'card';
  }
}

const out = {
  tool_called:          parsed.tool_called          || 'unknown',
  query_understood:     parsed.query_understood     || '',
  needs_input:          parsed.needs_input          === true,
  missing_param:        parsed.missing_param        || null,
  missing_param_prompt: parsed.missing_param_prompt || null,
  display_type,
  summary:              summary || `Returned ${rows.length} record(s).`,
  columns,
  rows,
  single_record:        (rows.length === 1 && display_type === 'card') ? rows[0] : (parsed.single_record || {}),
  boolean_result,
  total_count:          rows.length || (parsed.total_count || 0),
  error:                parsed.error === true,
  error_message:        parsed.error_message || null,
  timestamp:            new Date().toISOString()
};

return [{ json: out }];
